                                int[] outBuf, IntWrapper outPos) {
                DeltaZigzagEncoding.Decoder ctx = new DeltaZigzagEncoding.Decoder(0);

                int ip = inPos.get();
                int op = outPos.get();
                int vbcNum = 0, vbcShift = 24; // Variable Byte Context.
